public static long[] solve(String[] words) {
    int n = words.length;
    long[] answer = new long[n];

    if (n == 1) {
        return answer;
    }

    // Precompute the LCP for adjacent pairs in the original array
    int[] originalLCP = new int[n - 1];
    for (int i = 0; i < n - 1; i++) {
        originalLCP[i] = computeLCP(words[i], words[i + 1]);
    }

    for (int i = 0; i < n; i++) {
        if (n == 2) {
            // Only one adjacent pair possible, check if it's the one not removed
            if (i == 0) {
                answer[i] = computeLCP(words[1], words[2 >= n ? 1 : 2]);
            } else if (i == 1) {
                answer[i] = computeLCP(words[0], words[2 >= n ? 0 : 2]);
            }
            continue;
        }

        int maxLCP = 0;
        // Check adjacent pairs that are not affected by removal
        for (int j = 0; j < n - 1; j++) {
            if (j == i - 1) {
                // Pair (j, j+1) is affected if we remove j or j+1
                if (i - 1 >= 0 && i < n) {
                    int currentLCP = computeLCP(words[i - 1], words[i + 1]);
                    if (currentLCP > maxLCP) {
                        maxLCP = currentLCP;
                    }
                }
            } else if (j != i) {
                // Pair (j, j+1) is not affected if j+1 != i
                if (j + 1 != i) {
                    if (originalLCP[j] > maxLCP) {
                        maxLCP = originalLCP[j];
                    }
                }
            }
        }
        answer[i] = maxLCP;
    }

    return answer;
}

private static int computeLCP(String a, String b) {
    int minLen = Math.min(a.length(), b.length());
    int lcp = 0;
    while (lcp < minLen && a.charAt(lcp) == b.charAt(lcp)) {
